node -e "
const pluginNamePattern = /^(@[\\w-]+\\/)?nodebb-(theme|plugin|widget|rewards)-[\\w-]+$/;

console.log('Valid plugin names:');
console.log('nodebb-plugin-test:', pluginNamePattern.test('nodebb-plugin-test'));
console.log('@test/nodebb-plugin-test:', pluginNamePattern.test('@test/nodebb-plugin-test'));
console.log('nodebb-theme-test:', pluginNamePattern.test('nodebb-theme-test'));
console.log('nodebb-widget-test:', pluginNamePattern.test('nodebb-widget-test'));

console.log('\\nInvalid plugin names:');
console.log('notaplugin:', pluginNamePattern.test('notaplugin'));
console.log('\\t\\nnodebb-plugin:', pluginNamePattern.test('\\t\\nnodebb-plugin'));
console.log('nodebb-plugin:', pluginNamePattern.test('nodebb-plugin'));
console.log('nodebb-plugin-:', pluginNamePattern.test('nodebb-plugin-'));
"

node -e "
const { pluginNamePattern, themeNamePattern } = require('./src/constants');

console.log('Plugin Pattern:', pluginNamePattern);
console.log('Theme Pattern:', themeNamePattern);
console.log('\\n=== VALID Examples ===');
const validPlugins = [
  'nodebb-plugin-test',
  'nodebb-theme-harmony',
  'nodebb-widget-essentials',
  'nodebb-rewards-essentials',
  '@nodebb/nodebb-plugin-test',
];
validPlugins.forEach(p => console.log(\`  ✓ \${p}: \${pluginNamePattern.test(p)}\`));

console.log('\\n=== INVALID Examples (should reject) ===');
const invalidPlugins = [
  'notaplugin',
  '\\t\\nnodebb-plugin',
  'nodebb-plugin',
  'nodebb-plugin-',
  'plugin-test',
  'test plugin',
];
invalidPlugins.forEach(p => {
  try {
    console.log(\`  ✗ \${JSON.stringify(p)}: \${pluginNamePattern.test(p)}\`);
  } catch(e) {
    console.log(\`  ✗ \${JSON.stringify(p)}: ERROR\`);
  }
});
"

code_changes.new_string:
async function activate(plugin) {
	if (themeNamePattern.test(plugin)) {
		await reset.reset({
			theme: plugin,
		});
		process.exit();
	}
	try {
		await db.init();
		if (!pluginNamePattern.test(plugin)) {
			// Allow omission of `nodebb-plugin-`
			plugin = `nodebb-plugin-${plugin}`;
		}

		// Validate the plugin ID
		if (!pluginNamePattern.test(plugin)) {
			throw new Error('[[error:invalid-plugin-id]]');
		}

		plugin = await plugins.autocomplete(plugin);

